import React, { useState, useEffect, forwardRef, useImperativeHandle } from 'react';
import { MapContainer, TileLayer, Marker, Popup, GeoJSON, FeatureGroup, useMap, LayersControl } from 'react-leaflet';
import { EditControl } from "react-leaflet-draw";
import { GeoSearchControl, OpenStreetMapProvider } from 'leaflet-geosearch';
import 'leaflet/dist/leaflet.css';
import 'leaflet-draw/dist/leaflet.draw.css';
import 'leaflet-geosearch/dist/geosearch.css';
import L from 'leaflet';
import { kml } from "@tmcw/togeojson";
import API_URL from './config';

// Fix for default marker icon not showing correctly in some builds
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

const SearchControl = ({ visible }) => {
  const map = useMap();

  useEffect(() => {
    const provider = new OpenStreetMapProvider();

    const searchControl = new GeoSearchControl({
      provider: provider,
      style: 'bar',
      showMarker: true,
      showPopup: false,
      autoClose: true,
      retainZoomLevel: false,
      animateZoom: true,
      keepResult: true,
      searchLabel: 'Enter address',
    });

    map.addControl(searchControl);

    return () => map.removeControl(searchControl);
  }, [map]);

  // Handle visibility changes without recreating control
  useEffect(() => {
    const searchBar = document.querySelector('.leaflet-control-geosearch');
    if (searchBar) {
      if (visible) {
        searchBar.classList.remove('search-hidden');
      } else {
        searchBar.classList.add('search-hidden');
      }
    }
  }, [visible]);

  return null;
};

const MapComponent = forwardRef(({ chainage, offsetType, laneCount, kmlMergeOffset, onSaveSuccess, initialGeoJson }, ref) => {
  const position = [18.335, 73.853]; // Set a more relevant default (Pune area based on your data)
  const [geoJsonData, setGeoJsonData] = useState(null);
  const [isDataVisible, setIsDataVisible] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState({ show: false, message: '', type: '' });
  const featureGroupRef = React.useRef(null);

  // Set initial data if provided
  useEffect(() => {
    if (initialGeoJson) {
      setGeoJsonData(initialGeoJson);
      setIsDataVisible(true);
    }
  }, [initialGeoJson]);

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setIsDataVisible(true); // Hide search bar when uploading
      // 1. Upload file to server
      const formData = new FormData();
      formData.append('kmlFile', file);
      // Append current metadata to the upload
      formData.append('chainage', chainage);
      formData.append('offsetType', offsetType);
      formData.append('laneCount', laneCount);
      formData.append('kmlMergeOffset', kmlMergeOffset);

      fetch(`${API_URL}/upload-kml`, {
        method: 'POST',
        body: formData,
      })
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          console.log("File uploaded successfully to:", data.path);
          if (onSaveSuccess && data.pipelinePath) {
            onSaveSuccess(data.pipelinePath);
          }
        } else {
          console.error("Upload failed:", data.message);
        }
      })
      .catch(error => console.error("Error uploading file:", error));

      // 2. Read and display on map
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const text = event.target.result;
          const parser = new DOMParser();
          const kmlDoc = parser.parseFromString(text, "text/xml");
          const geojson = kml(kmlDoc);
          setGeoJsonData(geojson);
        } catch (error) {
          console.error("Error parsing KML file:", error);
          alert("Error parsing KML file");
          setIsDataVisible(false); // Show search bar again if failed
        }
      };
      reader.readAsText(file);
    }
  };

  // Zoom to layer when geoJsonData changes
  const ZoomToLayer = ({ data }) => {
    const map = useMap();
    useEffect(() => {
      if (data) {
        try {
          const layer = L.geoJSON(data);
          if (layer.getLayers().length > 0) {
            const bounds = layer.getBounds();
            if (bounds.isValid()) {
              map.fitBounds(bounds);
            }
          }
        } catch (e) {
          console.error("Error zooming to layer:", e);
        }
      }
    }, [data, map]);
    return null;
  };

  const handleSave = async () => {
    if (!featureGroupRef.current) return;
    
    // Get layers from the FeatureGroup where we draw
    const drawnLayers = featureGroupRef.current.getLayers();
    
    // Combine drawn features and uploaded features if any
    let allFeatures = drawnLayers.map(layer => layer.toGeoJSON());
    
    // If no drawn features, check if we have uploaded GeoJSON data
    if (allFeatures.length === 0 && geoJsonData && geoJsonData.features) {
      allFeatures = geoJsonData.features;
    }

    if (allFeatures.length === 0) {
      alert("Please draw something or upload a KML before saving.");
      return;
    }

    setIsSaving(true);
    setSaveStatus({ show: false, message: '', type: '' });

    const payload = {
      metadata: {
        chainage,
        offsetType,
        laneCount,
        kmlMergeOffset
      },
      geometry: allFeatures
    };

    try {
      const response = await fetch(`${API_URL}/save`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
      
      const result = await response.json();
      if (result.success) {
        setSaveStatus({ show: true, message: 'Data saved successfully!', type: 'success' });
        if (onSaveSuccess && result.pipelinePath) {
          onSaveSuccess(result.pipelinePath);
        }
        // Auto-hide success message after 3 seconds
        setTimeout(() => setSaveStatus(prev => ({ ...prev, show: false })), 3000);
      } else {
        setSaveStatus({ show: true, message: 'Error saving data: ' + result.message, type: 'error' });
      }
    } catch (error) {
      console.error("Error saving data:", error);
      setSaveStatus({ show: true, message: 'Error saving data to server. Make sure the server is running.', type: 'error' });
    } finally {
      setIsSaving(false);
    }
  };

  const handleClearAll = async (skipConfirm = false) => {
    if (!skipConfirm && !window.confirm("Are you sure you want to clear all data and layers? This will delete everything from the map and pipeline.")) {
      return;
    }

    try {
      // 1. Tell server to clear all data
      const response = await fetch(`${API_URL}/clear-all`, {
        method: 'POST'
      });
      
      const result = await response.json();
      if (result.success) {
        // 2. Clear local map layers
        if (featureGroupRef.current) {
          featureGroupRef.current.clearLayers();
        }
        setGeoJsonData(null);
        setIsDataVisible(false);
        
        if (!skipConfirm) {
          alert("All data and layers cleared successfully!");
        }
        if (onSaveSuccess) {
          onSaveSuccess(''); // Reset last saved path
        }
      } else {
        alert("Error clearing data: " + result.message);
      }
    } catch (error) {
      console.error("Error clearing data:", error);
      alert("Error clearing data on server.");
    }
  };

  useImperativeHandle(ref, () => ({
    handleSave,
    handleClearAll
  }));

  const _onCreated = (e) => {
    console.log("Created: ", e);
    setIsDataVisible(true); // Hide search bar when drawing starts
  };

  const _onEdited = (e) => {
    console.log("Edited: ", e);
  };

  const _onDeleted = async (e) => {
    console.log("Deleted layers: ", e);
    
    // Check if the map is now effectively empty
    const remainingDrawnLayers = featureGroupRef.current ? featureGroupRef.current.getLayers().length : 0;
    
    // If all drawn layers are gone, we check if we should also clear uploaded data
    // and trigger backend cleanup. 
    if (remainingDrawnLayers === 0) {
      setIsDataVisible(false);
      
      // If the user used "Clear All" or deleted the last layer, 
      // we assume they want a clean slate.
      await handleClearAll(true); 
    }
  };

  return (
    <div className="map-wrapper" style={{ position: 'relative' }}>
      {isSaving && (
        <div className="loading-overlay">
          <div className="loading-spinner"></div>
          <p>Saving data...</p>
        </div>
      )}
      
      {saveStatus.show && (
        <div className={`save-status-toast ${saveStatus.type}`}>
          {saveStatus.type === 'success' ? '✓ ' : '✕ '}
          {saveStatus.message}
        </div>
      )}

      <div className="kml-upload-container">
        <label htmlFor="kml-upload" className="kml-upload-label">
          Upload KML
        </label>
        <input
          id="kml-upload"
          type="file"
          accept=".kml"
          onChange={handleFileChange}
          style={{ display: 'none' }}
        />
      </div>
      <MapContainer center={position} zoom={18} scrollWheelZoom={true} maxZoom={24} style={{ height: '100%', width: '100%' }}>
        <SearchControl visible={!isDataVisible} />
        <LayersControl position="topright">
          <LayersControl.BaseLayer checked name="Google Streets">
            <TileLayer
              url="http://{s}.google.com/vt/lyrs=m&x={x}&y={y}&z={z}"
              maxZoom={24}
              maxNativeZoom={20}
              subdomains={['mt0', 'mt1', 'mt2', 'mt3']}
            />
          </LayersControl.BaseLayer>
          <LayersControl.BaseLayer name="Google Satellite">
            <TileLayer
              url="http://{s}.google.com/vt/lyrs=s,h&x={x}&y={y}&z={z}"
              maxZoom={24}
              maxNativeZoom={20}
              subdomains={['mt0', 'mt1', 'mt2', 'mt3']}
            />
          </LayersControl.BaseLayer>
        </LayersControl>
        <FeatureGroup ref={featureGroupRef}>
          <EditControl
            position='topleft'
            onEdited={_onEdited}
            onCreated={_onCreated}
            onDeleted={_onDeleted}
            draw={{
              rectangle: false,
              circle: false,
              circlemarker: false,
              marker: true,
              polyline: true,
              polygon: true,
            }}
          />
        </FeatureGroup>
        <Marker position={position}>
          <Popup>
            A pretty CSS3 popup. <br /> Easily customizable.
          </Popup>
        </Marker>
        {geoJsonData && (
          <>
            <GeoJSON data={geoJsonData} />
            <ZoomToLayer data={geoJsonData} />
          </>
        )}
      </MapContainer>
    </div>
  );
});

export default MapComponent;
